class StringUtils {
    public static int countVowels(String s) {
        s = s.toLowerCase();
        int count = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
                count++;
            }
        }
        return count;
    }
}

public class App {
    public static void main(String[] args) {
        System.out.println("Vowels in 'Hello World': " + StringUtils.countVowels("Hello World"));
    }
}

