class Temperature {
    private final double celsius;

    private Temperature(double celsius) {
        this.celsius = celsius;
    }

    public static Temperature fromCelsius(double c) {
        return new Temperature(c);
    }

    public static Temperature fromFahrenheit(double f) {
        return new Temperature((f - 32) / 1.8);
    }

    public static Temperature fromKelvin(double k) {
        return new Temperature(k - 273.15);
    }

    public double getCelsius() {
        return celsius;
    }

    @Override
    public String toString() {
        return celsius + "°C";
    }
}

public class App {
    public static void main(String[] args) {
        Temperature t1 = Temperature.fromCelsius(100);
        Temperature t2 = Temperature.fromFahrenheit(212);
        Temperature t3 = Temperature.fromKelvin(373.15);

        System.out.println(t1);
        System.out.println(t2);
        System.out.println(t3);
    }
}

class MathExtra {
    public static final double PI = 3.14159265358979;
    public static final double GOLDEN_RATIO = 1.61803398874989;

    private MathExtra() {}

    public static double circleArea(double r) {
        return PI * r * r;
    }

    public static int fibonacci(int n) {
        if (n <= 1) return 1;
        int a = 1, b = 1;
        for (int i = 2; i < n; i++) {
            int c = a + b;
            a = b;
            b = c;
        }
        return b;
    }
}

public class App {
    public static void main(String[] args) {
        System.out.println("Circle area (r=5): " + MathExtra.circleArea(5));
        System.out.println("Fib(7): " + MathExtra.fibonacci(7));
    }
}

