    private Boolean2(boolean value) {
        this.value = value;
    }

    public static Boolean2 of(boolean b) {
        return b ? TRUE : FALSE;
    }

    public boolean isTrue() {
        return value;
    }
}

public class App {
    public static void main(String[] args) {
        Boolean2 a = Boolean2.of(true);
        Boolean2 b = Boolean2.of(true);
        System.out.println("Same instance: " + (a == b));
