class UnitConverter {
    public static final double KG_TO_LB = 2.20462;
    public static final double KM_TO_MILES = 0.621371;
    public static final double C_TO_F_MULT = 1.8;
    public static final double C_TO_F_ADD = 32;

    private UnitConverter() {}

    public static double kgToLbs(double kg) {
        return kg * KG_TO_LB;
    }

    public static double kmToMiles(double km) {
        return km * KM_TO_MILES;
    }

    public static double celsiusToFahrenheit(double c) {
        return c * C_TO_F_MULT + C_TO_F_ADD;
    }
}

public class App {
    public static void main(String[] args) {
        System.out.println("70 kg = " + UnitConverter.kgToLbs(70) + " lbs");
        System.out.println("5 km = " + UnitConverter.kmToMiles(5) + " miles");
        System.out.println("100°C = " + UnitConverter.celsiusToFahrenheit(100) + "°F");
    }
}

class Service {
    private final String name;
    private final String version;

    public Service(String name, String version) {
        this.name = name;
        this.version = version;
    }

    public String getName() { return name; }
    public String getVersion() { return version; }

    @Override
    public String toString() {
        return "Service[name=" + name + ", version=" + version + "]";
    }
}

class ServiceRegistry {
    private static final Service[] registered = new Service[10];
    private static int count = 0;

    private ServiceRegistry() {}

    public static void register(Service s) {
        if (count < registered.length) {
            registered[count++] = s;
        }
    }

    public static Service findByName(String name) {
        for (int i = 0; i < count; i++) {
            if (registered[i].getName().equals(name)) {
                return registered[i];
            }
        }
        return null;
    }

    public static void printAll() {
        System.out.println("All services:");
        for (int i = 0; i < count; i++) {
            System.out.println(registered[i]);
        }
    }

    public static int getCount() {
        return count;
    }
}

public class App {
    public static void main(String[] args) {
        ServiceRegistry.register(new Service("Auth", "1.0"));
        ServiceRegistry.register(new Service("Payment", "2.1"));
        ServiceRegistry.register(new Service("Notification", "1.5"));

        System.out.println("Registered services: " + ServiceRegistry.getCount());

        Service found = ServiceRegistry.findByName("Payment");
        System.out.println("Found: " + found);

        ServiceRegistry.printAll();
    }
}
